import React, { useState, useRef } from 'react';
import { nextId } from './adminConfig';
import './AdminShared.css';
import './AdminProducts.css';

// ── Supabase storage helper ──────────────────────────────
// Adjust BUCKET_NAME to match your Supabase storage bucket
const SUPABASE_URL    = process.env.REACT_APP_SUPABASE_URL    || '';
const SUPABASE_ANON   = process.env.REACT_APP_SUPABASE_ANON_KEY || '';
const BUCKET_NAME     = 'product-images';

async function uploadImageToSupabase(file, productName) {
  if (!SUPABASE_URL || !SUPABASE_ANON) {
    // Fallback: return a local object URL for preview when Supabase is not configured
    return URL.createObjectURL(file);
  }
  const ext      = file.name.split('.').pop();
  const fileName = `${productName.replace(/\s+/g, '-').toLowerCase()}-${Date.now()}-${Math.random().toString(36).slice(2)}.${ext}`;
  const res = await fetch(
    `${SUPABASE_URL}/storage/v1/object/${BUCKET_NAME}/${fileName}`,
    {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${SUPABASE_ANON}`,
        'Content-Type': file.type,
        'x-upsert': 'false',
      },
      body: file,
    }
  );
  if (!res.ok) throw new Error(`Upload failed: ${res.statusText}`);
  return `${SUPABASE_URL}/storage/v1/object/public/${BUCKET_NAME}/${fileName}`;
}

// ── Component ────────────────────────────────────────────
export default function AdminProducts({ products, setProducts, categories, showToast }) {
  const [modal,   setModal]   = useState(null);   // null | 'add' | product-obj
  const [confirm, setConfirm] = useState(null);

  const emptyForm = {
    name: '', emoji: '🌿', price: '', category: categories[0]?.name || '',
    description: '', weight: '', origin: '', benefits: '',
    images: [],   // ← array of URLs (up to 4)
  };
  const [form,       setForm]       = useState(emptyForm);
  const [uploading,  setUploading]  = useState(false);
  const [previewIdx, setPreviewIdx] = useState(0);
  const fileInputRef = useRef();

  function openAdd()  { setForm(emptyForm); setPreviewIdx(0); setModal('add'); }
  function openEdit(p) {
    setForm({
      ...p,
      benefits: Array.isArray(p.benefits) ? p.benefits.join(', ') : (p.benefits || ''),
      images:   Array.isArray(p.images)   ? [...p.images]          : (p.image_url ? [p.image_url] : []),
    });
    setPreviewIdx(0);
    setModal(p);
  }

  // ── Handle file selection ────────────────────────────
  async function handleFileSelect(e) {
    const files = Array.from(e.target.files);
    if (!files.length) return;

    const remaining = 4 - form.images.length;
    if (remaining <= 0) {
      showToast('Maximum 4 images allowed. Remove one first.', false);
      return;
    }
    const toUpload = files.slice(0, remaining);
    setUploading(true);
    try {
      const urls = await Promise.all(
        toUpload.map((f) => uploadImageToSupabase(f, form.name || 'product'))
      );
      setForm((prev) => ({ ...prev, images: [...prev.images, ...urls] }));
      showToast(`${urls.length} image${urls.length > 1 ? 's' : ''} uploaded ✓`);
    } catch (err) {
      showToast(`Upload failed: ${err.message}`, false);
    } finally {
      setUploading(false);
      e.target.value = '';
    }
  }

  function removeImage(idx) {
    setForm((prev) => {
      const next = prev.images.filter((_, i) => i !== idx);
      return { ...prev, images: next };
    });
    setPreviewIdx((i) => Math.max(0, i - 1));
  }

  function moveImage(from, to) {
    setForm((prev) => {
      const imgs = [...prev.images];
      const [item] = imgs.splice(from, 1);
      imgs.splice(to, 0, item);
      return { ...prev, images: imgs };
    });
  }

  // ── Save ─────────────────────────────────────────────
  function save() {
    if (!form.name.trim() || !form.price.trim()) {
      showToast('Name & Price are required', false);
      return;
    }
    const benefitsArr = (form.benefits || '')
      .split(',').map((s) => s.trim()).filter(Boolean);

    const record = {
      ...form,
      benefits: benefitsArr,
      images:   form.images,
      // keep legacy image_url = first image for backward compat
      image_url: form.images[0] || '',
    };

    if (modal === 'add') {
      setProducts((prev) => [...prev, { ...record, id: nextId(prev) }]);
      showToast('Product added ✓');
    } else {
      setProducts((prev) =>
        prev.map((p) => (p.id === modal.id ? { ...record, id: modal.id } : p))
      );
      showToast('Product updated ✓');
    }
    setModal(null);
  }

  function askDelete(id) {
    setConfirm({
      msg: 'Delete this product? This cannot be undone.',
      onOk: () => {
        setProducts((prev) => prev.filter((p) => p.id !== id));
        showToast('Product deleted');
      },
    });
  }

  // ─────────────────────────────────────────────────────
  return (
    <div>
      {/* Header row */}
      <div className="adm-section-hdr">
        <h2 className="adm-section-title">Product Management</h2>
        <button className="adm-btn adm-btn--green" onClick={openAdd}>+ Add Product</button>
      </div>

      {/* Table */}
      <div className="adm-table-wrap">
        <table className="adm-table">
          <thead>
            <tr>
              <th>Image</th>
              <th>Name</th>
              <th>Category</th>
              <th>Price</th>
              <th>Origin</th>
              <th>Actions</th>
            </tr>
          </thead>
          <tbody>
            {products.map((p) => {
              const cat       = categories.find((c) => c.name === p.category);
              const thumbUrl  = p.images?.[0] || p.image_url || null;
              return (
                <tr key={p.id}>
                  <td>
                    {thumbUrl ? (
                      <img
                        src={thumbUrl} alt={p.name}
                        style={{ width: 52, height: 40, objectFit: 'cover', borderRadius: 6 }}
                      />
                    ) : (
                      <span style={{ fontSize: 28 }}>{p.emoji}</span>
                    )}
                    {(p.images?.length > 1) && (
                      <span style={{ fontSize: 10, color: '#6ddc9a', display: 'block' }}>
                        +{p.images.length - 1} more
                      </span>
                    )}
                  </td>
                  <td className="adm-table__name">{p.name}</td>
                  <td>
                    <span
                      className="adm-badge"
                      style={{ background: cat?.bg || '#e8f8ee', color: cat?.color || '#1a6b3a' }}
                    >
                      {p.category}
                    </span>
                  </td>
                  <td className="adm-table__price">{p.price}</td>
                  <td className="adm-table__muted">{p.origin}</td>
                  <td>
                    <div className="adm-action-btns">
                      <button className="adm-btn adm-btn--edit" onClick={() => openEdit(p)}>✏️ Edit</button>
                      <button className="adm-btn adm-btn--red"  onClick={() => askDelete(p.id)}>🗑️ Delete</button>
                    </div>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
        {products.length === 0 && (
          <div className="adm-empty">No products yet. Click "+ Add Product" to get started.</div>
        )}
      </div>

      {/* ── ADD / EDIT MODAL ─────────────────────── */}
      {modal !== null && (
        <div className="adm-modal-bg" onClick={() => setModal(null)}>
          <div className="adm-modal adm-modal--wide" onClick={(e) => e.stopPropagation()}>
            <div className="adm-modal__hdr">
              <span className="adm-modal__title">{modal === 'add' ? 'Add New Product' : 'Edit Product'}</span>
              <button className="adm-modal__close" onClick={() => setModal(null)}>×</button>
            </div>
            <div className="adm-modal__body">

              {/* ── IMAGES SECTION ───────────────────── */}
              <div className="adm-images-section">
                <label className="adm-label">
                  Product Images
                  <span className="adm-label-hint"> (up to 4 — first image is the cover)</span>
                </label>

                {/* Preview + thumbnails */}
                {form.images.length > 0 && (
                  <div className="adm-img-preview-wrap">
                    {/* Big preview */}
                    <div className="adm-img-preview-main">
                      <img src={form.images[previewIdx]} alt="preview" />
                      <button
                        className="adm-img-remove-btn"
                        onClick={() => removeImage(previewIdx)}
                        title="Remove this image"
                      >×</button>
                    </div>
                    {/* Thumbs */}
                    <div className="adm-img-thumbs">
                      {form.images.map((url, i) => (
                        <div
                          key={i}
                          className={`adm-img-thumb ${i === previewIdx ? 'adm-img-thumb--active' : ''}`}
                          onClick={() => setPreviewIdx(i)}
                        >
                          <img src={url} alt={`img ${i + 1}`} />
                          {i === 0 && <span className="adm-img-cover-label">Cover</span>}
                          {/* Move left/right arrows */}
                          {i > 0 && (
                            <button
                              className="adm-img-move adm-img-move--left"
                              onClick={(e) => { e.stopPropagation(); moveImage(i, i - 1); }}
                              title="Move left"
                            >‹</button>
                          )}
                          {i < form.images.length - 1 && (
                            <button
                              className="adm-img-move adm-img-move--right"
                              onClick={(e) => { e.stopPropagation(); moveImage(i, i + 1); }}
                              title="Move right"
                            >›</button>
                          )}
                        </div>
                      ))}
                    </div>
                  </div>
                )}

                {/* Upload button */}
                {form.images.length < 4 && (
                  <div className="adm-img-upload-row">
                    <input
                      ref={fileInputRef}
                      type="file"
                      accept="image/*"
                      multiple
                      style={{ display: 'none' }}
                      onChange={handleFileSelect}
                    />
                    <button
                      className="adm-btn adm-btn--upload"
                      onClick={() => fileInputRef.current.click()}
                      disabled={uploading}
                    >
                      {uploading ? '⏳ Uploading…' : `📷 Add Images (${form.images.length}/4)`}
                    </button>
                    <span className="adm-label-hint">
                      {4 - form.images.length} slot{4 - form.images.length !== 1 ? 's' : ''} remaining
                    </span>
                  </div>
                )}
                {form.images.length === 4 && (
                  <p className="adm-label-hint" style={{ marginTop: 6 }}>
                    ✅ Maximum 4 images reached. Remove one to add another.
                  </p>
                )}
              </div>

              {/* Row 1: emoji + name */}
              <div className="adm-row">
                <div className="adm-field adm-field--small">
                  <label className="adm-label">Emoji</label>
                  <input className="adm-input adm-input--emoji" value={form.emoji}
                    onChange={(e) => setForm((f) => ({ ...f, emoji: e.target.value }))} maxLength={4} />
                </div>
                <div className="adm-field">
                  <label className="adm-label">Product Name *</label>
                  <input className="adm-input" placeholder="e.g. Organic Rice" value={form.name}
                    onChange={(e) => setForm((f) => ({ ...f, name: e.target.value }))} />
                </div>
              </div>

              {/* Row 2: price + category */}
              <div className="adm-row">
                <div className="adm-field">
                  <label className="adm-label">Price *</label>
                  <input className="adm-input" placeholder="e.g. ₹80/kg" value={form.price}
                    onChange={(e) => setForm((f) => ({ ...f, price: e.target.value }))} />
                </div>
                <div className="adm-field">
                  <label className="adm-label">Category</label>
                  <select className="adm-input" value={form.category}
                    onChange={(e) => setForm((f) => ({ ...f, category: e.target.value }))}>
                    {categories.map((c) => <option key={c.name} value={c.name}>{c.name}</option>)}
                  </select>
                </div>
              </div>

              {/* Row 3: origin + weight */}
              <div className="adm-row">
                <div className="adm-field">
                  <label className="adm-label">Origin</label>
                  <input className="adm-input" placeholder="e.g. Guntur, AP" value={form.origin}
                    onChange={(e) => setForm((f) => ({ ...f, origin: e.target.value }))} />
                </div>
                <div className="adm-field">
                  <label className="adm-label">Weight / Pack Sizes</label>
                  <input className="adm-input" placeholder="e.g. 250g, 500g, 1kg" value={form.weight}
                    onChange={(e) => setForm((f) => ({ ...f, weight: e.target.value }))} />
                </div>
              </div>

              {/* Description */}
              <div className="adm-field" style={{ marginBottom: 18 }}>
                <label className="adm-label">Description</label>
                <textarea className="adm-input adm-textarea" rows={3} placeholder="Product description…"
                  value={form.description}
                  onChange={(e) => setForm((f) => ({ ...f, description: e.target.value }))} />
              </div>

              {/* Benefits */}
              <div className="adm-field" style={{ marginBottom: 28 }}>
                <label className="adm-label">Benefits (comma separated)</label>
                <input className="adm-input" placeholder="e.g. Chemical-free, Rich in nutrients"
                  value={form.benefits}
                  onChange={(e) => setForm((f) => ({ ...f, benefits: e.target.value }))} />
              </div>

              {/* Actions */}
              <div className="adm-modal__actions">
                <button className="adm-btn adm-btn--cancel" onClick={() => setModal(null)}>Cancel</button>
                <button className="adm-btn adm-btn--green adm-btn--wide" onClick={save}>
                  {modal === 'add' ? 'Add Product' : 'Save Changes'}
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* ── CONFIRM DELETE ─────────────────────────── */}
      {confirm && (
        <div className="adm-confirm-bg">
          <div className="adm-confirm">
            <p className="adm-confirm__msg">⚠️ {confirm.msg}</p>
            <div className="adm-confirm__actions">
              <button className="adm-btn adm-btn--cancel" onClick={() => setConfirm(null)}>Cancel</button>
              <button className="adm-btn adm-btn--red" onClick={() => { confirm.onOk(); setConfirm(null); }}>Delete</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
